"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Menu, X, ArrowRight } from "lucide-react";
import { Button } from "@/components/ui/Button";

interface NavbarProps {
  onOpenContact: () => void;
}

export function Navbar({ onOpenContact }: NavbarProps) {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const showLogo = typeof window !== 'undefined' ? window.scrollY > 450 : false;
  const [isLogoVisible, setIsLogoVisible] = useState(false);

  useEffect(() => {
      const handleScrollLogo = () => {
          setIsLogoVisible(window.scrollY > 450);
      }
      window.addEventListener("scroll", handleScrollLogo);
      return () => window.removeEventListener("scroll", handleScrollLogo);
  }, []);

  const navLinks = [
    { name: "Work", href: "#work" },
    { name: "Certifications", href: "#certifications" },
    { name: "Experience", href: "#experience" },
    { name: "Internship", href: "#internship" },
    { name: "Skills", href: "#skills" },
    { name: "About", href: "#about" },
  ];

  return (
    <>
      <motion.nav
        initial={{ y: -100 }}
        animate={{ y: 0 }}
        transition={{ duration: 0.8, ease: [0.25, 0.4, 0.25, 1] }}
        className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
          isScrolled ? "py-4 bg-background/80 backdrop-blur-md border-b border-white/5" : "py-8 bg-transparent"
        }`}
      >
        <div className="px-6 md:px-12 max-w-[1400px] mx-auto flex justify-between items-center">
          {/* Logo */}
          <a href="#" className={`text-2xl font-heading font-bold uppercase tracking-tighter z-50 relative transition-opacity duration-500 ${isLogoVisible ? 'opacity-100' : 'opacity-0'}`}>
            RITIK
          </a>

          {/* Desktop Nav */}
          <div className="hidden md:flex items-center gap-8">
            {navLinks.map((link) => (
              <a
                key={link.name}
                href={link.href}
                className="text-sm font-medium text-white/70 hover:text-white transition-colors"
              >
                {link.name}
              </a>
            ))}
          </div>

          {/* Right Side */}
          <div className="hidden md:flex items-center gap-4">
             <div className="flex items-center gap-2 text-xs font-medium mr-4">
                <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse" />
                <span className="text-white/80">Available for project</span>
             </div>
            <Button onClick={onOpenContact} size="sm" className="rounded-full px-6 border-white/20 hover:bg-white hover:text-black transition-colors">
              LET'S TALK
            </Button>
          </div>

          {/* Mobile Toggle */}
          <button
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            className="md:hidden z-50 relative w-10 h-10 flex items-center justify-center rounded-full border border-white/20"
          >
            {isMobileMenuOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
          </button>
        </div>
      </motion.nav>

      {/* Mobile Menu Overlay */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <motion.div
            initial={{ opacity: 0, clipPath: "circle(0% at 100% 0%)" }}
            animate={{ opacity: 1, clipPath: "circle(150% at 100% 0%)" }}
            exit={{ opacity: 0, clipPath: "circle(0% at 100% 0%)" }}
            transition={{ duration: 0.5, ease: "easeInOut" }}
            className="fixed inset-0 bg-black z-40 flex flex-col justify-center px-6"
          >
            <div className="flex flex-col gap-8">
              {navLinks.map((link, i) => (
                <motion.a
                  key={link.name}
                  href={link.href}
                  onClick={() => setIsMobileMenuOpen(false)}
                  initial={{ opacity: 0, x: -50 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.1 + i * 0.1 }}
                  className="text-5xl font-heading font-bold uppercase text-white/90 hover:text-accent transition-colors"
                >
                  {link.name}
                </motion.a>
              ))}
              <motion.div
                 initial={{ opacity: 0, y: 20 }}
                 animate={{ opacity: 1, y: 0 }}
                 transition={{ delay: 0.5 }}
              >
                 <Button onClick={() => { onOpenContact(); setIsMobileMenuOpen(false); }} className="w-full text-xl py-6 mt-8">
                    Let's Talk <ArrowRight className="ml-2" />
                 </Button>
              </motion.div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}
